const raw = $input.first().json.data || $input.first().json.body || '';
const text = typeof raw === 'string' ? raw : String(raw);

// Parser de CSV com separador ';' tolerante a aspas
function parseCSV(str) {
  const rows = [];
  let row = [], field = '', inQuotes = false;
  for (let i = 0; i < str.length; i++) {
    const c = str[i];
    if (inQuotes) {
      if (c === '"' && str[i + 1] === '"') { field += '"'; i++; }
      else if (c === '"') inQuotes = false;
      else field += c;
    } else {
      if (c === '"') inQuotes = true;
      else if (c === ';') { row.push(field); field = ''; }
      else if (c === '\n') { row.push(field); rows.push(row); row = []; field = ''; }
      else if (c === '\r') { /* ignora */ }
      else field += c;
    }
  }
  if (field.length || row.length) { row.push(field); rows.push(row); }
  return rows;
}

const rows = parseCSV(text).filter(r => r.length > 1);
if (rows.length < 2) throw new Error('CSV vazio ou ilegivel.');

const header = rows[0].map(h => (h || '').trim());
const idx = name => header.indexOf(name);

function toFloat(v) {
  if (v == null) return 0.0;
  let s = String(v).replace('%', '').replace(',', '.').trim();
  const n = parseFloat(s);
  return isNaN(n) ? 0.0 : n;
}
function clean(v) {
  if (v == null) return null;
  const s = String(v).trim();
  return s.length ? s : null;
}

const col = {
  sap: idx('CÓDIGO SAP'),
  apres: idx('APRESENTAÇÃO'),
  princ: idx('PRINCIPIO ATIVO'),
  ean: idx('CÓDIGO EAN'),
  fam: idx('FAMÍLIA'),
  tipo: idx('TIPO DE MEDICAMENTO'),
  registro: idx('REGISTRO MS'),
  ncm: idx('NCM (CLASS FISCAL)'),
  pis: idx('% Pis'),
  cofins: idx('% Cofins'),
  i0pf: idx('ICMS 0 % (PF)'), i0pmc: idx('ICMS 0 % (PMC)'),
  i12pf: idx('ICMS 12 %  (PF)'), i12pmc: idx('ICMS 12 % (PMC) '),
  i17pf: idx('ICMS 17 % (PF)'), i17pmc: idx('ICMS 17 % (PMC)'),
  i175pf: idx('ICMS 17,5 % (PF)'), i175pmc: idx('ICMS 17,5 % (PMC)'),
  i18pf: idx('ICMS 18 %  (PF)'), i18pmc: idx('ICMS 18 %  (PMC)'),
  i20pf: idx('ICMS 20 % (PF)'), i20pmc: idx('ICMS 20 % (PMC)')
};

const out = [];
for (let r = 1; r < rows.length; r++) {
  const row = rows[r];
  const codigo_sap = clean(row[col.sap]);
  const apresentacao = clean(row[col.apres]);
  if (!codigo_sap || !apresentacao) continue;

  const principio_ativo = clean(row[col.princ]);
  const ean = clean(row[col.ean]);
  const familia = clean(row[col.fam]);
  const tipo = clean(row[col.tipo]);

  const page_content = 'Apresentação: ' + apresentacao +
    '. Princípio Ativo: ' + (principio_ativo || '') +
    '. Código SAP: ' + codigo_sap +
    '. Código EAN: ' + (ean || '') +
    '. Família: ' + (familia || '') +
    '. Tipo: ' + (tipo || '') + '.';

  const metadata = {
    codigo_sap, apresentacao, principio_ativo,
    registro_ms: clean(row[col.registro]),
    ncm: clean(row[col.ncm]),
    pis_perc: toFloat(row[col.pis]),
    cofins_perc: toFloat(row[col.cofins]),
    icms_0_pf: toFloat(row[col.i0pf]), icms_0_pmc: toFloat(row[col.i0pmc]),
    icms_12_pf: toFloat(row[col.i12pf]), icms_12_pmc: toFloat(row[col.i12pmc]),
    icms_17_pf: toFloat(row[col.i17pf]), icms_17_pmc: toFloat(row[col.i17pmc]),
    icms_17_5_pf: toFloat(row[col.i175pf]), icms_17_5_pmc: toFloat(row[col.i175pmc]),
    icms_18_pf: toFloat(row[col.i18pf]), icms_18_pmc: toFloat(row[col.i18pmc]),
    icms_20_pf: toFloat(row[col.i20pf]), icms_20_pmc: toFloat(row[col.i20pmc])
  };

  out.push({ json: { chunk_id: 'sap_' + codigo_sap, page_content, metadata } });
}

if (out.length === 0) throw new Error('Nenhum produto valido gerado a partir do CSV.');
return out;

const emb = $input.first().json;
const chunk = $('Loop Lotes').item.json;
const embedding = emb.data && emb.data[0] ? emb.data[0].embedding : null;
if (!embedding || embedding.length !== 1024) {
  throw new Error('Embedding invalido para chunk ' + chunk.chunk_id + ' (dim ' + (embedding ? embedding.length : 'null') + ').');
}

const linha = {
  chunk_id: chunk.chunk_id,
  content: chunk.page_content,
  metadata: JSON.stringify(chunk.metadata),
  embedding: '[' + embedding.join(',') + ']'
};

// Acumula as linhas no static data do workflow (persiste entre iteracoes do loop).
// Assim, ao fim do loop, "Coletar Linhas" tem TODAS as linhas para um unico upsert.
const store = $getWorkflowStaticData('global');
if (!Array.isArray(store.linhas)) store.linhas = [];
store.linhas.push(linha);

return [{ json: linha }];

// Le todas as linhas acumuladas no static data ao longo do loop e limpa o
// acumulador (para uma proxima execucao comecar do zero).
const store = $getWorkflowStaticData('global');
const linhas = Array.isArray(store.linhas) ? store.linhas : [];
store.linhas = [];

if (linhas.length === 0) {
  throw new Error('Nenhuma linha montada para inserir (o loop nao produziu dados).');
}
// Emite uma linha por item -> o Upsert nativo processa todas numa unica transacao.
return linhas.map(json => ({ json }));

const item = $input.first() ? $input.first().json : {};
const err = item.error || {};

// Procura a mensagem mais especifica disponivel (varia conforme o no/erro).
let msg = 'Falha durante a ingestao.';
const candidatos = [
  typeof item.error === 'string' ? item.error : null,
  err && err.description,
  err && err.cause && err.cause.message,
  err && Array.isArray(err.messages) && err.messages.length ? err.messages.join(' | ') : null,
  err && err.message,
  item.message
].filter(Boolean);
if (candidatos.length) msg = candidatos[0];

// A etiqueta da etapa vem do no Set anterior; se faltar, infere pela mensagem.
let etapa = item._etapa;
let componente = item._componente;
if (!etapa) {
  const t = (msg || '').toLowerCase();
  if (/sql|postgres|relation|column|database|vector|pgvector|duplicate|constraint/.test(t)) {
    etapa = 'Upsert no banco'; componente = 'banco vetorial (Supabase/pgvector)';
  } else if (/timeout|econnrefused|fetch|socket|network|enotfound|http|connect/.test(t)) {
    etapa = 'Geracao de embedding'; componente = 'embeddings (LM Studio)';
  } else if (/csv|ilegivel|vazio|produto valido/.test(t)) {
    etapa = 'Geracao de chunks'; componente = 'parsing do CSV';
  } else {
    etapa = 'Ingestao'; componente = 'fluxo interno';
  }
}

const relatorio = '[INGESTAO FALHOU] etapa: ' + etapa + ' | componente: ' + componente + ' | erro: ' + msg;
return [{ json: { status: 'erro', etapa, componente, erro: msg, relatorio } }];
